457	async function findSessionContaining(needle: string) {
458	  const sessions = await discoverClaudeSessions({ claudeHomeDir })
459	
460	  return findFirstSessionMatching(sessions, async candidate => {
461	    const content = await readFile(candidate.transcriptPath, 'utf8')
462	    return content.includes(needle)
463	  })
464	}
