466	async function findFirstSessionMatching<T>(
467	  items: T[],
468	  predicate: (item: T) => Promise<boolean>,
469	): Promise<T | undefined> {
470	  for (const item of items) {
471	    if (await predicate(item)) {
472	      return item
473	    }
474	  }
475	
476	  return undefined
